mapper.update:
UPDATE student_admin_class
SET student_id = #{studentId},
    admin_class_id = #{adminClassId},
    enroll_year = #{enrollYear},
    status = #{status}
WHERE id = #{id}

mapper.select:
SELECT sac.*, s.name as student_name, ac.class_name, ac.class_code
FROM student_admin_class sac
LEFT JOIN student s ON sac.student_id COLLATE utf8mb4_unicode_ci = s.username COLLATE utf8mb4_unicode_ci
LEFT JOIN admin_class ac ON sac.admin_class_id = ac.id


        AND sac.student_id LIKE CONCAT('%', #{studentId}, '%')


        AND sac.admin_class_id = #{adminClassId}


        AND sac.enroll_year = #{enrollYear}


        AND sac.status = #{status}


ORDER BY sac.enroll_year DESC, ac.class_name
